  if type(a) ~= "table" then return nil end
  if a.incomingInvites ~= nil or a.activeTrade ~= nil then return a end
  local inner = a[1]
  if type(inner) == "table" and (inner.incomingInvites ~= nil or inner.activeTrade ~= nil) then return inner end
  return nil
end

