  local ok, err = pcall(function()
    local ch = TextChatService:WaitForChild("TextChannels", 5):WaitForChild("RBXGeneral", 5)
    ch:SendAsync(text)
  end)
  return ok, err
end
M.sendChat = sendChat

local function buildListings(cfg, feed, owned)
  local listings = {}
  for name, override in pairs(cfg.items or {}) do
    if override.forSale then
      if (not owned) or (owned[name] and owned[name] > 0) then
        local q = pricing.quote(cfg, feed[name] or {}, override, 1)
        if q then listings[#listings + 1] = { name = name, ask = q.ask } end
      end
    end
  end
  return listings
