  Main:Toggle({ Title = "Enable Universal Auto-Trade", Value = cfg.enabled,
    Callback = function(v) cfg.enabled = v; save(cfg); if deps.onToggleEnabled then deps.onToggleEnabled(v) end end })
  Main:Toggle({ Title = "Test Mode (accepts + adds item, never confirms)", Value = cfg.testMode ~= false,
    Callback = function(v) cfg.testMode = v; save(cfg) end })

  -- Active vend item: the single item the bot sells in every trade.
  local vendNames = { "(highest-value For Sale)" }
  do
    local ns = {}
    for name in pairs(deps.feed) do ns[#ns + 1] = name end
    table.sort(ns)
    for _, n in ipairs(ns) do vendNames[#vendNames + 1] = n end
  end
  Main:Dropdown({ Title = "Active Vend Item (what it sells)", Values = vendNames,
    Value = (cfg.activeVendItem ~= "" and cfg.activeVendItem) or vendNames[1],
    Callback = function(sel)
      if sel == vendNames[1] then cfg.activeVendItem = "" else
        cfg.activeVendItem = sel
        cfg.items[sel] = cfg.items[sel] or {}; cfg.items[sel].forSale = true
      end
      save(cfg)
    end })
  Main:Slider({ Title = "Global Markup %", Step = 1,
    Value = { Min = 0, Max = 50, Default = cfg.globalMarkupPct },
    Callback = function(v) cfg.globalMarkupPct = v; save(cfg) end })
  Main:Slider({ Title = "Negotiation Band %", Step = 1,
    Value = { Min = 0, Max = 30, Default = cfg.bandPct },
    Callback = function(v) cfg.bandPct = v; save(cfg) end })
  Main:Toggle({ Title = "Demand Scaling", Value = cfg.demandScaling,
    Callback = function(v) cfg.demandScaling = v; save(cfg) end })
  Main:Dropdown({ Title = "Trade Unit Mode",
    Values = { "single_copy", "single_type_qty", "multi_basket" },
    Value = cfg.tradeUnitMode,
    Callback = function(v) cfg.tradeUnitMode = v; save(cfg) end })
  Main:Toggle({ Title = "Rotating Chat Ads", Value = cfg.ads.rotatingAds,
    Callback = function(v) cfg.ads.rotatingAds = v; save(cfg) end })
  Main:Toggle({ Title = "Auto-Invite Nearby", Value = cfg.ads.autoInvite,
    Callback = function(v) cfg.ads.autoInvite = v; save(cfg) end })
  Main:Toggle({ Title = "Ads: In-Stock Only", Value = cfg.ads.stockOnly,
    Callback = function(v) cfg.ads.stockOnly = v; save(cfg) end })

  -- ---- Items tab (per-item for-sale + overrides) ----
  local names = {}
  for name in pairs(deps.feed) do names[#names + 1] = name end
  table.sort(names)
  local selected = names[1]
  Items:Dropdown({ Title = "Select Item", Values = names, Value = names[1],
    Callback = function(sel) selected = sel end })
  Items:Toggle({ Title = "Selected: For Sale", Value = false,
    Callback = function(v)
      if not selected then return end
      cfg.items[selected] = cfg.items[selected] or {}
      cfg.items[selected].forSale = v; save(cfg) end })
  Items:Input({ Title = "Selected: Price Override (blank = use value)",
    Callback = function(txt)
      if not selected then return end
      cfg.items[selected] = cfg.items[selected] or {}
      cfg.items[selected].value = tonumber(txt); save(cfg) end })
  Items:Toggle({ Title = "Selected: Want to Buy (cap mode)", Value = false,
    Callback = function(v)
      if not selected then return end
      cfg.buy[selected] = cfg.buy[selected] or {}
      cfg.buy[selected].wantBuy = v; save(cfg) end })

  -- ---- Safety / 24-7 tab ----
  Safety:Toggle({ Title = "Auto-Buyer at Gem Cap", Value = cfg.buyEnabled,
    Callback = function(v) cfg.buyEnabled = v; save(cfg) end })
  Safety:Input({ Title = "Gem Cap (default 100000000)",
    Callback = function(txt) cfg.gemCap = tonumber(txt) or cfg.gemCap; save(cfg) end })
  Safety:Input({ Title = "Buy Discount % (default 10)",
    Callback = function(txt) cfg.buyDiscountPct = tonumber(txt) or cfg.buyDiscountPct; save(cfg) end })
  Safety:Input({ Title = "Player Cooldown sec (default 30)",
    Callback = function(txt) cfg.cooldownSec = tonumber(txt) or cfg.cooldownSec; save(cfg) end })
  Safety:Toggle({ Title = "Auto-Reconnect", Value = cfg.survival.autoReconnect,
    Callback = function(v) cfg.survival.autoReconnect = v; save(cfg) end })
  Safety:Toggle({ Title = "Anti-AFK", Value = cfg.survival.antiAfk,
    Callback = function(v) cfg.survival.antiAfk = v; save(cfg) end })
  Safety:Input({ Title = "Discord Webhook URL (blank = off)",
    Callback = function(txt) cfg.webhook.url = txt or ""; save(cfg) end })

  local handle = { window = Window, status = statusParagraph }
  function handle.setStatus(text)
    pcall(function() statusParagraph:SetDesc(text) end)
  end
  function handle.notify(text)
    pcall(function() WindUI:Notify({ Title = "Auto-Trade", Content = text, Duration = 8 }) end)
  end
  return handle
end

return M

end)()
-- === main ===
-- Universal Auto-Trade - STANDALONE. Does not load the obfuscated base; it talks
-- to the game directly (workspace.__THINGS.__REMOTES + Framework.Library) and
-- builds its own WindUI window. Only external deps: WindUI + the value feed.
local CONFIG = {
  feedUrl = "https://raw.githubusercontent.com/0xfray/Mr-script/refs/heads/main/MR/value.lua",
  version = "v1.3-standalone",
}

local libConfig  = __M["lib.config"]
local libFeed    = __M["lib.feed"]
local capmode    = __M["lib.capmode"]
local libStats   = __M["lib.stats"]
local LogBuf     = __M["lib.logbuf"]
local dump       = __M["lib.dump"]
local remotesM   = __M["runtime.remotes"]
local gamedata   = __M["runtime.gamedata"]
local persist    = __M["runtime.persist"]
local inventory  = __M["runtime.inventory"]
local prober     = __M["runtime.prober"]
local TradeM     = __M["runtime.trade"]
local advertiser = __M["runtime.advertiser"]
local survival   = __M["runtime.survival"]
local webhookSend= __M["runtime.webhook_send"]
local cooldownLib= __M["lib.cooldown"]
local ui         = __M["runtime.ui"]

local dbg = LogBuf.new(600)
local function nows() return string.format("%.2fs", os.clock()) end
local function logp(t) print("[AutoTrade] " .. t); dbg:info(t, nows()) end
local function logstep(t) print("[AutoTrade] * " .. t); dbg:step(t, nows()) end
local function logwarn(t) warn("[AutoTrade] " .. t); dbg:warn(t, nows()) end
local function logok(t) print("[AutoTrade] OK " .. t); dbg:ok(t, nows()) end
local function logDump(label, tbl) dbg:info(label .. ":", nows()); for _, l in ipairs(dump.lines(tbl, { maxDepth = 3, maxKeys = 40 })) do dbg:info("  " .. l, nows()) end end

logstep("boot " .. CONFIG.version)

local cfg = libConfig.merge(libConfig.defaults(), persist.loadSettings() or {})
logok("settings loaded (enabled=" .. tostring(cfg.enabled) .. ")")

local function fetchFeed()
  local ok, raw = pcall(function() return loadstring(game:HttpGet(CONFIG.feedUrl))() end)
  if ok and type(raw) == "table" then persist.saveFeedCache(raw); return libFeed.normalize(raw) end
  return nil, raw
end
local feed, feedErr = fetchFeed()
if feed then logok("feed fetched (" .. libFeed.count(feed) .. " items)")
else feed = libFeed.normalize(persist.loadFeedCache() or {})
  logwarn("feed fetch failed (" .. tostring(feedErr) .. "); cache=" .. libFeed.count(feed) .. " items") end

local statsObj = persist.loadStats() or libStats.new(os.time())
local function onEvent(event, data) pcall(webhookSend.send, cfg, event, data) end

local function copyReport()
  local r = dbg:report("AutoTrade " .. CONFIG.version)
  if setclipboard then pcall(setclipboard, r) elseif toclipboard then pcall(toclipboard, r) end
  print(r)
end
local uiHandle = ui.build({ cfg = cfg, feed = feed, save = persist.saveSettings, stats = statsObj,
  debug = { copy = copyReport, print = function() print(dbg:report("AutoTrade " .. CONFIG.version)) end },
  onToggleEnabled = function() end })
if uiHandle then logok("WindUI panel loaded") else logwarn("WindUI panel FAILED to load") end
local function setStatus(t) if uiHandle and uiHandle.setStatus then uiHandle.setStatus(t) end end

local wrongPlace = cfg.expectedPlaceId and game.PlaceId ~= cfg.expectedPlaceId
local remotes, rroot
if wrongPlace then
  logwarn(("WRONG GAME: place=%s (need Trading Plaza %s)"):format(tostring(game.PlaceId), tostring(cfg.expectedPlaceId)))
  setStatus("Wrong game. Open Trading Plaza (13200523806), then reload.")
  if uiHandle and uiHandle.notify then uiHandle.notify("Open Trading Plaza to trade.") end
else
  setStatus("Connecting to game...")
  logstep("resolving remotes (workspace.__THINGS.__REMOTES)")
  local rerr; remotes, rerr = remotesM.resolveRemotes(20)
  if remotes then logok("remotes resolved via " .. tostring(rerr)) else logwarn("remotes NOT resolved: " .. tostring(rerr)) end
  logstep("acquiring Framework Library root")
  local rooterr; rroot, rooterr = gamedata.root(20)
  if rroot then logok("Library root acquired") else logwarn("Library root FAILED: " .. tostring(rooterr)) end
end

logstep("probing environment"); pcall(function() prober.run(dbg, nows()) end); logok("probe complete")

survival.startAntiAfk(cfg); survival.startReconnect(cfg, onEvent)
logok("survival started")

if remotes and rroot then
  local catalog = gamedata.catalog(rroot)
  local catCount = 0; for _ in pairs(catalog) do catCount = catCount + 1 end
  logok("item catalog built (" .. tostring(catCount) .. " ids)")
  if catCount <= 4 then logwarn("catalog nearly empty - additem will only work for Wave/Ocean until the id source is confirmed") end

  local latestStatus
  local dumpedStatus, dumpedAT, dumpedInvite = false, false, false
  local function getActiveTrade() return latestStatus and latestStatus.activeTrade end
  local function getGems() return gamedata.gems() end
  local function sendTradeMsg(text) pcall(function() remotes.trading_sendmessage:FireServer(text) end) end

  local cooldownState = {}
  local function gate(name)
    local t = os.time(); local okg = cooldownLib.allow(cfg, name, cooldownState[name], t)
    if okg then cooldownState[name] = t end; return okg
  end
  local lastMode = "sell"
  local function mode()
    local gems = getGems(); local m = capmode.mode(cfg, gems, lastMode)
    if m ~= lastMode then
      logp(("mode %s -> %s (gems=%s cap=%s buyEnabled=%s)"):format(lastMode, m, tostring(gems), tostring(cfg.gemCap), tostring(cfg.buyEnabled)))
    end
    if m == "buy" and lastMode ~= "buy" then onEvent("cap", { gems = gems }) end
    lastMode = m; return m
  end
  -- Sell the configured Active Vend Item; else the highest-value For Sale item.
  local function pickSellItem(_at)
    if cfg.activeVendItem and cfg.activeVendItem ~= "" then return cfg.activeVendItem end
    local best, bestVal
    for name, ov in pairs(cfg.items or {}) do
      if ov.forSale then
        local v = (feed[name] and feed[name].value) or 0
        if not bestVal or v > bestVal then best = name; bestVal = v end
      end
    end
    return best
  end
  local function pickBuyItem(at)
    local offered = at and (at.offeredItemsTarget)
    if type(offered) == "table" then for _, it in pairs(offered) do local c = (type(it) == "table" and (it.class or it.className or it.name)) or it; if c and cfg.buy[c] and cfg.buy[c].wantBuy then return c end end end
    return nil
  end
  local function onSold(item, qty, gems, cost)
    libStats.recordSell(statsObj, gems, cost); persist.saveStats(statsObj)
    onEvent("sale", { item = item, qty = qty, gems = gems, profit = gems - cost })
    logp(("SOLD %s x%d for %s"):format(item, qty, tostring(gems))); setStatus(("Sold %s x%d for %s"):format(item, qty, tostring(gems)))
  end
  local function onBought(item, qty, gems)
    libStats.recordBuy(statsObj, gems); persist.saveStats(statsObj)
    onEvent("buy", { item = item, qty = qty, gems = gems })
    logp(("BOUGHT %s x%d for %s"):format(item, qty, tostring(gems))); setStatus(("Bought %s x%d for %s"):format(item, qty, tostring(gems)))
  end

  local runner = TradeM.new({
    remotes = remotes, cfg = cfg, feed = feed, catalog = catalog,
    getActiveTrade = getActiveTrade, sendTradeMsg = sendTradeMsg,
    pickSellItem = pickSellItem, pickBuyItem = pickBuyItem,
    log = logp, mode = mode, gate = gate, onSold = onSold, onBought = onBought,
  })

  -- Single gated entry point for accepting an invite. gate() dedups both the
  -- poll path and the event path (per-player cooldown), so no double-processing.
  local function playerName(p)
    if type(p) == "userdata" then local ok, n = pcall(function() return p.Name end); return ok and n or "?" end
    return tostring(p)
  end
  local function tryHandleInvite(uid, player)
    if not cfg.enabled or not uid then return end
    if not gate(uid) then return end -- cooldown / dedup
    logp(("HANDLING invite from %s uid=%s"):format(playerName(player), tostring(uid)))
    runner:handle({ uid = uid, player = player, name = playerName(player) })
  end

  -- Cache status; accept invites from incomingInvites (entry = {inviter,target,timestamp}).
  local function processStatus(s)
    if type(s) ~= "table" then return end
    latestStatus = s
    if not dumpedStatus then
      dumpedStatus = true
      logDump("status (trimmed)", { activeTrade = s.activeTrade, incomingInvites = s.incomingInvites, outgoingInvites = s.outgoingInvites })
    end
    if type(s.activeTrade) == "table" and not dumpedAT then dumpedAT = true; logDump("activeTrade fields", s.activeTrade) end
    local inv = s.incomingInvites
    if type(inv) == "table" then
      for uid, entry in pairs(inv) do
        if not dumpedInvite then dumpedInvite = true; logDump("incomingInvites entry", (type(entry) == "table" and entry) or { value = entry }) end
        local player = (type(entry) == "table" and (entry.inviter or entry.player)) or nil
        tryHandleInvite(uid, player)
      end
    end
  end

  local function connectStatus(name)
    local r = remotes[name]
    if r and r.OnClientEvent then
      r.OnClientEvent:Connect(function(a) processStatus(gamedata.unwrapStatus(a)) end)
      logok("listening on " .. name)
    end
  end
  connectStatus("trading_statuschange"); connectStatus("trading_tradebegan")

  -- Event path: inviter arrives as a Player. Funnel through the same gate.
  local dumpedInviteEvt = false
  if remotes.trading_invitesent then
    remotes.trading_invitesent.OnClientEvent:Connect(function(...)
      local args = { ... }
      if not dumpedInviteEvt then dumpedInviteEvt = true; logDump("trading_invitesent args", args) end
      local a = args[1]
      local inviter = (type(a) == "table" and a[1]) or a
      local uid
      if type(inviter) == "userdata" then pcall(function() uid = inviter.UserId end)
      elseif type(inviter) == "table" then uid = inviter.uid or inviter.id or inviter.UserId
      else uid = inviter end
      tryHandleInvite(uid, inviter)
    end)
    logok("listening on trading_invitesent")
  else
    logwarn("trading_invitesent absent")
  end

  -- Poll getStatus as the reliable driver (matches the base's polling model).
  local ticks = 0
  survival.watchdog(cfg, "trade-loop", function()
    while true do
      ticks = ticks + 1
      local s = gamedata.getStatus(remotes)
      if s then processStatus(s) end
      if ticks % 15 == 1 then
        local invCount = 0
        if latestStatus and type(latestStatus.incomingInvites) == "table" then
          for _ in pairs(latestStatus.incomingInvites) do invCount = invCount + 1 end
        end
        logp(("heartbeat: enabled=%s activeTrade=%s invites=%s gems=%s"):format(
          tostring(cfg.enabled), tostring(getActiveTrade() ~= nil), tostring(invCount), tostring(getGems())))
      end
      task.wait(1)
    end
  end, onEvent)

  advertiser.start({ cfg = cfg, feed = feed, ownedFn = inventory.owned, log = logp })
  setStatus("Ready. Trading " .. (cfg.enabled and "ENABLED" or "disabled") .. ". items=" .. libFeed.count(feed))
  logok("trading wired")
elseif not wrongPlace then
  setStatus("Not fully wired (remotes=" .. tostring(remotes ~= nil) .. " root=" .. tostring(rroot ~= nil) .. ").")
end

if (cfg.feedRefreshSec or 0) > 0 then
  task.spawn(function()
    while true do
      task.wait(cfg.feedRefreshSec)
      local fresh = fetchFeed()
      if fresh then for k in pairs(feed) do feed[k] = nil end; for k, v in pairs(fresh) do feed[k] = v end; logp("feed refreshed") end
    end
  end)
end

logstep("ready. items=" .. libFeed.count(feed) .. " remotes=" .. tostring(remotes ~= nil) .. " root=" .. tostring(rroot ~= nil))
logp("Send someone a trade / get an invite, then Copy Debug Report so I can confirm the shapes.")
